{"command": "source ~/.openclaw/workspace-son/.env && curl -s -X POST "https://api.minimaxi.com/v1/music_generation" \
  -H "Authorization: Bearer $MINIMAX_API_KEY" \
  -H "Content-Type: application/json" \
  -d '{
    "model": "music-2.6",
    "prompt": "诡异可爱的曲风，带有电子音乐元素和童谣感。描述6月1日诡异降临之夜，一个胆小的小萝莉戴着猫耳和猫尾，穿着小白袜系着项圈，24小时陪聊驱散恐惧。节奏中等偏慢，旋律既要诡异神秘又要可爱温馨，像黑暗童话中的摇篮曲。",
    "lyrics_optimizer": true,
    "is_instrumental": false,
    "output_format": "url"
  }' 2>&1", "timeout": 120}
